local LxBaseMgr = require("LApp.Manager.LxBaseMgr")
---@class LxTimerMgr:LxBaseMgr
local LxTimerMgr = classX("LxTimerMgr", LxBaseMgr)

local LxNTimer = LxNTimer
local LxNFrameTimer = LxNFrameTimer

function LxTimerMgr:Initialize()
    LxBaseMgr.Initialize(self)

    self._timers = {}
    self._stopFunc = function(timer)
        self:_OnTimerStop(timer)
    end

    self._timerIds = {}
    local count = 500
    for k = 1, count do
        table.insert(self._timerIds, k)
    end
    self._freeIdCount = count
    self._requestTimerIdMax = count

    ---timer对象池
    self._unusedTimers = {}
    self._unusedFrameTimers = {}
end

function LxTimerMgr:LogStatus()
    local cnt = 0
    for k,v in pairs(self._timers or {}) do
        cnt = cnt + 1
    end
    LogWarn("timers count=" ..cnt ..", the free timerId count "..#self._timerIds)
    LogWarn("unused timers count = " ..#self._unusedTimers )
    LogWarn("unused  frame timers count = " ..#self._unusedFrameTimers)
end

function LxTimerMgr:GetTimerId()
    if self._freeIdCount > 0 then
        self._freeIdCount = self._freeIdCount - 1
        local timerId = table.remove(self._timerIds)
        return timerId
    else
        local timerId = self._timerIdMax + 1
        self._timerIdMax = timerId
        return timerId
    end
end

function LxTimerMgr:AddTimer(timer)
    local id = self:GetTimerId()
    timer.id = id
    if self._timers[id] then
        LogError(">>> timer id is duplicated ...")
    end
    self._timers[id] = timer
end

function LxTimerMgr:_OnTimerStop(timer)
    self:RemoveTimer(timer)
end

function LxTimerMgr:_InternalGetUnusedTimer()
    if #self._unusedTimers > 0 then
        return table.remove(self._unusedTimers)
    end
end

function LxTimerMgr:_InternalGetUnusedFrameTimer()
    if #self._unusedFrameTimers > 0 then
        return table.remove(self._unusedFrameTimers)
    end
end

function LxTimerMgr:NewTimeTimer(func, selfObj, duration, loop, unscaled)
    local timer = self:_InternalGetUnusedTimer()
    if timer ~= nil then
        timer:Reset(func, selfObj, duration, loop, unscaled)
    else
        timer = LxNTimer.New(func, selfObj, duration,loop, unscaled)
    end
    self:AddTimer(timer)
    timer:Start()
    return timer
end

function LxTimerMgr:NewFrameTimer(func, selfObj, duration, loop, unscaled)
    local timer = self:_InternalGetUnusedFrameTimer()
    if timer ~= nil then
        timer:Reset(func, selfObj, duration, loop)
    else
        timer = LxNFrameTimer.New(func, selfObj, duration, loop)
    end
    self:AddTimer(timer)
    timer:Start()
    return timer
end

function LxTimerMgr:DelayTime(func, selfObj, duration, unscaled)
    local timer = self:_InternalGetUnusedTimer()
    if timer ~= nil then
        timer:Reset(func, selfObj, duration, 1, unscaled)
        timer.stopFunc = self._stopFunc
    else
        timer = LxNTimer.New(func, selfObj, duration, 1, unscaled, self._stopFunc)
    end
    self:AddTimer(timer)
    timer:Start()
    return timer
end

function LxTimerMgr:DelayFrame(func, selfObj, duration, unscaled)
    local timer = self:_InternalGetUnusedFrameTimer()
    if timer ~= nil then
        timer:Reset(func, selfObj, duration, 1)
        timer.stopFunc = self._stopFunc
    else
        timer = LxNFrameTimer.New(func, selfObj, duration, 1, self._stopFunc)
    end
    self:AddTimer(timer)
    timer:Start()
    return timer
end

---@param timer LxNTimer
function LxTimerMgr:RemoveTimer(timer)
    if not timer then return end
    if timer.running then
        timer:Stop()
    end
    timer:Recycle()

    local id = timer.id
    local oldTimer = self._timers[id]
    if oldTimer == timer then
        self._timers[id] = nil
        table.insert(self._timerIds, id)
        self._freeIdCount = self._freeIdCount + 1

        if timer.timerType == 1 then
            table.insert(self._unusedTimers,  timer)
        elseif timer.timerType == 2 then
            table.insert(self._unusedFrameTimers, timer)
        end
    end
end

function LxTimerMgr:Dispose()
    if self._isDisposed then return end
    
    local timers = self._timers
    for k,v in pairs(timers) do
        v:Dispose()
        timers[k] = nil
    end

    timers = self._unusedTimers
    for k, v in ipairs(timers) do
        v:Dispose()
    end
    self._unusedTimers = {}

    timers = self._unusedFrameTimers
    for k,v in ipairs(timers) do
        v:Dispose()
    end
    self._unusedFrameTimers = {}

    self._stopFunc = nil
    LxBaseMgr.Dispose(self)
end

function LxTimerMgr:ClearAllTimers()
    local timers = self._timers
    for k,v in pairs(timers) do
        v:Dispose()
        timers[k] = nil
    end
    self._stopFunc = nil
end


return LxTimerMgr
